#include <stdio.h>

// Binary Logic Gate Functions in C
// Fundamental building blocks of all digital systems

// NOT Gate: Inverter - returns complement of input
int NOT(int a) {
 return (a == 1) ? 0 : 1;
}

// AND Gate: Returns 1 only if ALL inputs are 1
int AND(int a, int b) {
 return (a == 1 && b == 1) ? 1 : 0;
}

// OR Gate: Returns 1 if ANY input is 1
int OR(int a, int b) {
 return (a == 1 || b == 1) ? 1 : 0;
}

// NAND Gate: NOT-AND (complement of AND)
int NAND(int a, int b) {
 return NOT(AND(a, b));
}

// NOR Gate: NOT-OR (complement of OR)
int NOR(int a, int b) {
 return NOT(OR(a, b));
}

// XOR Gate: Exclusive-OR - 1 if inputs are DIFFERENT
// Algebraic: F = A'B + AB'
int XOR(int a, int b) {
 return (a != b) ? 1 : 0;
}

// XNOR Gate: Exclusive-NOR - 1 if inputs are SAME
// Algebraic: F = AB + A'B' = (XOR)'
int XNOR(int a, int b) {
 return (a == b) ? 1 : 0;
}

// Function to generate complete truth table
void generateTruthTable() {
 int a, b;

 printf("=============================================================\n");
 printf(" BINARY LOGIC GATE TRUTH TABLES (2-Input Gates)\n");
 printf("=============================================================\n");
 printf(" A B | AND OR NOT-A NAND NOR XOR XNOR\n");
 printf("-------|-------------------------------------------\n");

 for (a = 0; a <= 1; a++) {
 for (b = 0; b <= 1; b++) {
 printf(" %d %d | %d %d %d %d %d %d %d\n",
 a, b,
 AND(a, b),
 OR(a, b),
 NOT(a),
 NAND(a, b),
 NOR(a, b),
 XOR(a, b),
 XNOR(a, b));
 }
 }
 printf("=============================================================\n\n");
}

// Verify XOR using algebraic expression: F = A'B + AB'
void verifyXORExpression() {
 int a, b, term1, term2, xor_result;

 printf("XOR Verification using F = A'B + AB'\n");
 printf("--------------------------------------\n");

 for (a = 0; a <= 1; a++) {
 for (b = 0; b <= 1; b++) {
 // A'B = NOT(A) AND B
 term1 = AND(NOT(a), b);
 // AB' = A AND NOT(B)
 term2 = AND(a, NOT(b));
 // F = A'B + AB' = OR(term1, term2)
 xor_result = OR(term1, term2);

 printf("A=%d B=%d: A'B=%d, AB'=%d, XOR=%d (using F=A'B+AB')\n",
 a, b, term1, term2, xor_result);
 }
 }
 printf("\n");
}

// Half Adder demonstration - uses XOR for Sum, AND for Carry
void halfAdderDemo() {
 int a, b, sum, carry;

 printf("Real-World Application: Half Adder Circuit\n");
 printf("-------------------------------------------\n");
 printf("Half Adder uses XOR for SUM and AND for CARRY\n\n");
 printf(" A B | SUM CARRY\n");
 printf("------|------------\n");

 for (a = 0; a <= 1; a++) {
 for (b = 0; b <= 1; b++) {
 sum = XOR(a, b); // Sum bit from XOR
 carry = AND(a, b); // Carry bit from AND
 printf(" %d %d | %d %d\n", a, b, sum, carry);
 }
 }
 printf("\nThis is the foundation of binary addition in CPUs!\n");
}

// Main function
int main() {
 printf("\n*** BINARY LOGIC GATES IMPLEMENTATION IN C ***\n\n");

 // Generate complete truth table
 generateTruthTable();

 // Verify XOR algebraic expression
 verifyXORExpression();

 // Half Adder demonstration
 halfAdderDemo();

 return 0;
}
